// ============================================================
// EXTRAE contexto del mensaje entrante de Telegram
// ============================================================
const msg = $input.first().json.message;

const chatId     = msg.chat.id;
const userId     = msg.from.id;
const firstName  = msg.from.first_name || 'amigo';
const text       = msg.text || msg.caption || '';
const hasPhoto   = !!(msg.photo && msg.photo.length > 0);
const hasVoice   = !!msg.voice;
const hasMedia   = hasPhoto || hasVoice;

// Fecha y hora argentina
const ahora = new Date();
const fechaAR = ahora.toLocaleDateString('es-AR');
const horaAR  = ahora.toLocaleTimeString('es-AR', { hour: '2-digit', minute: '2-digit' });
const diaSemana = ahora.toLocaleDateString('es-AR', { weekday: 'long' });

return [{ json: {
  chatId, userId, firstName, text, hasMedia, hasPhoto, hasVoice,
  fechaAR, horaAR, diaSemana,
  rawMessage: msg
}}];

// ============================================================
// PARSEA la respuesta del AI Agent
// Detecta si hay ACCION: REGISTRAR, ACCION: CONSULTA o solo chat
// ============================================================
const rawOutput = $input.first().json.output || '';

// --- Detectar REGISTRAR ---
const accionRegistrar =
  rawOutput.includes('ACCION: REGISTRAR') ||
  rawOutput.includes('Registro') ||
  rawOutput.includes('"destino"');

const textoUsuario = (($('Prompt').first().json.text) || '').toLowerCase().trim();

const accionConsulta =
  /ACCION:\s*CONSULTA/i.test(rawOutput) ||
  /"filtro_tipo"\s*:/i.test(rawOutput) ||
  textoUsuario.includes('cuanto gaste') ||
  textoUsuario.includes('qué gasté') ||
  textoUsuario.includes('que gaste') ||
  textoUsuario.includes('gaste hoy') ||
  textoUsuario.includes('gaste este mes') ||
  textoUsuario.includes('gaste esta semana') ||
  textoUsuario.includes('balance') ||
  textoUsuario.includes('resumen') ||
  textoUsuario.includes('mis ingresos') ||
  textoUsuario.includes('cuanto ingrese') ||
  textoUsuario.includes('cuanto gane') ||
  textoUsuario.includes('ver ingresos');

let jsonData = null;
let mensajeBot = rawOutput;

if (accionRegistrar || accionConsulta) {
  const jsonMatch = rawOutput.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      jsonData = JSON.parse(jsonMatch[0]);

      // FIX: si Gemini manda categoria=Ingresos, forzar filtro_tipo ingresos
      if (jsonData.filtro_tipo === 'categoria') {
        const cat = (jsonData.filtro_categoria || '').toLowerCase().trim();
        if (cat === 'ingresos' || cat === 'ingreso') {
          jsonData.filtro_tipo = 'ingresos';
          jsonData.filtro_categoria = '';
        }
      }

    } catch(e) {
      jsonData = null;
    }
  }
  // El mensaje para el usuario es todo lo que viene DESPUÉS del JSON
  const afterJson = rawOutput.split(/\}[^\{]*$/);
  mensajeBot = afterJson[afterJson.length - 1]?.trim() || '';

  // Si el mensaje quedó vacío, tomamos lo anterior al JSON
  if (!mensajeBot) {
    const beforeJson = rawOutput.split('ACCION:')[0]?.trim();
    mensajeBot = beforeJson || '✅ Entendido!';
  }
}

// Limpiar el mensaje (quitar el bloque técnico)
mensajeBot = mensajeBot
  .replace(/ACCION: REGISTRAR/g, '')
  .replace(/ACCION: CONSULTA/g, '')
  .replace(/\{[\s\S]*?\}/g, '')
  .trim();

if (!mensajeBot) mensajeBot = accionRegistrar ? '✅ Movimiento anotado!' : '🔍 Buscando los datos...';

// Recuperar contexto del nodo anterior en la cadena
const ctxNode = $('Prompt').first().json;

return [{ json: {
  chatId:    ctxNode.chatId,
  firstName: ctxNode.firstName,
  fechaAR:   ctxNode.fechaAR,
  accion: accionRegistrar ? 'REGISTRAR' : accionConsulta ? 'CONSULTA' : 'CHAT',
  jsonData,
  mensajeBot,
  rawOutput
}}];

// ============================================================
// FIN - Normalizar Gasto (con conversión USD → ARS)
// ============================================================
const item = $input.first().json;
const d = item.jsonData || {};

function safeNumber(v, def = 0) { const n = Number(v); return Number.isFinite(n) ? n : def; }
function safeString(v, def = '') { return (v === null || v === undefined) ? def : String(v); }

const allowed = [
  'Ingresos','Costos fijos','Alimentacion','Mascotas',
  'Productos Hogar','Salidas y Entretenimiento','Delivery',
  'Gastos Extraordinarios','Tarjetas','Transporte',
  'Actividades','Salud'
];

// Normalizar destino
const destinoRaw = safeString(d.destino).trim().toLowerCase();
let destino = 'Registro';
if (destinoRaw === 'cuotas') destino = 'Cuotas';
if (destinoRaw === 'inversiones' || destinoRaw === 'inversion') destino = 'Inversiones';

// Normalizar tipo
const tipoRaw = safeString(d.tipo).trim().toLowerCase();
const tipo = (tipoRaw === 'ingreso' || tipoRaw === 'ingresos') ? 'Ingreso' : 'Gasto';

// Normalizar moneda
const monedaRaw = safeString(d.moneda).trim().toUpperCase();
const moneda = ['ARS','USD'].includes(monedaRaw) ? monedaRaw : 'ARS';

// Normalizar categoría
let categoria = safeString(d.categoria, 'Gastos Extraordinarios').trim();
if (!allowed.includes(categoria)) categoria = 'Gastos Extraordinarios';
if (tipo === 'Ingreso') categoria = 'Ingresos';

const montoOriginal = safeNumber(d.monto, 0);

// ── Obtener tipo de cambio en tiempo real ─────────────────────
let tipoCambio = 0;
try {
  const res = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://dolarapi.com/v1/dolares/oficial'
  });
  tipoCambio = Number(res.venta) || 0;
} catch(e) {
  tipoCambio = 0;
}

// ── Calcular Monto ARS ────────────────────────────────────────
let montoArs = montoOriginal;
if (moneda === 'USD' && tipoCambio > 0) {
  montoArs = Math.round(montoOriginal * tipoCambio);
}

// ── Mensaje de confirmación ───────────────────────────────────
const firstName = item.firstName || 'vos';
let mensajeBot;
if (moneda === 'USD' && tipoCambio > 0) {
  mensajeBot = `✅ Listo! Anoté *${safeString(d.concepto)}* por *$${montoOriginal.toLocaleString('es-AR')} USD* (= *$${montoArs.toLocaleString('es-AR')} ARS* al TC $${tipoCambio}) en *${categoria}* 💵\n\n¿Gastaste algo más, ${firstName}? 😊`;
} else {
  mensajeBot = `✅ Listo! Anoté *${safeString(d.concepto)}* por *$${montoOriginal.toLocaleString('es-AR')} ARS* en *${categoria}* 💸\n\n¿Gastaste algo más, ${firstName}? 😊`;
}

return [{ json: {
  chatId:         item.chatId,
  firstName,
  fechaAR:        item.fechaAR,
  mensajeBot,
  accion:         item.accion,
  destino,
  monto:          montoOriginal,
  moneda,
  montoArs,
  concepto:       safeString(d.concepto, 'N/A').trim() || 'N/A',
  categoria,
  tipo,
  cuotas_totales: Math.max(1, Math.floor(safeNumber(d.cuotas_totales, 1))),
  tarjeta:        safeString(d.tarjeta, 'No especificada').trim() || 'No especificada',
  ticker:         safeString(d.ticker, 'N/A').trim() || 'N/A',
  cantidad:       Math.max(1, safeNumber(d.cantidad, 1)),
  fecha_inicio:   safeString(d.fecha_inicio, item.fechaAR).trim() || item.fechaAR,
  tipoCambio
}}];

const rows = $input.all();
const meta = $('CONSULTA').first().json;

const filtroTipo = meta.filtro_tipo || 'total';
const filtroCat  = meta.filtro_categoria || '';
const firstName  = meta.firstName || 'vos';
const chatId     = meta.chatId;

function parseDate(val) {
  if (!val) return null;
  const s = String(val).trim();
  if (/^\d{1,2}\/\d{1,2}\/\d{4}$/.test(s)) {
    const [d, m, y] = s.split('/');
    return new Date(parseInt(y), parseInt(m)-1, parseInt(d));
  }
  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d;
}

const hoy = new Date();
const inicioMes    = new Date(hoy.getFullYear(), hoy.getMonth(), 1);
const inicioSemana = new Date(hoy); inicioSemana.setDate(hoy.getDate() - 6); inicioSemana.setHours(0,0,0,0);
const inicioDia    = new Date(hoy); inicioDia.setHours(0,0,0,0);

function enRango(row) {
  const fecha = parseDate(row.json['Fecha'] || row.json['fecha']);
  if (!fecha) return filtroTipo === 'total';
  if (filtroTipo === 'mes')    return fecha >= inicioMes;
  if (filtroTipo === 'semana') return fecha >= inicioSemana;
  if (filtroTipo === 'hoy')    return fecha >= inicioDia;
  return true;
}

function coincideCategoria(row) {
  if (filtroTipo !== 'categoria' || !filtroCat) return true;
  const cat = String(row.json.Categoria || '').toLowerCase().trim();
  return cat.includes(filtroCat.toLowerCase().trim());
}

// ── Acumuladores ──────────────────────────────────────────────
let gastosARS      = 0;
let gastosUSD      = 0;
let gastosUSDenARS = 0;
let ingresos       = 0;
const porCategoria = {};

for (const row of rows) {
  if (!enRango(row) || !coincideCategoria(row)) continue;
  const montoOriginal = Number(row.json['Monto Original'] || 0);
  const montoArs      = Number(row.json['Monto Ars'] || 0);
  const moneda        = String(row.json['Moneda'] || 'ARS').trim().toUpperCase();
  const tipo          = String(row.json['Tipo'] || '').trim();
  const cat           = String(row.json['Categoria'] || 'Sin categoria').trim();

  // FIX: usa montoOriginal como fallback siempre, no solo para ARS
  const montoParaCalculo = montoArs > 0 ? montoArs : montoOriginal;

  if (tipo === 'Gasto') {
    if (moneda === 'USD') {
      gastosUSD      += montoOriginal;
      gastosUSDenARS += montoArs > 0 ? montoArs : 0;
    } else {
      gastosARS += montoOriginal;
    }
    porCategoria[cat] = (porCategoria[cat] || 0) + montoParaCalculo;
  } else if (tipo === 'Ingreso') {
    ingresos += montoParaCalculo;
  }
}

const totalGastosARS = gastosARS + gastosUSDenARS;

const topCats = Object.entries(porCategoria)
  .sort((a,b) => b[1]-a[1]).slice(0,5)
  .map(([cat, monto]) => `  • ${cat}: $${Math.round(monto).toLocaleString('es-AR')} ARS`);

// ── CASO ESPECIAL: INGRESOS ───────────────────────────────────
if (filtroTipo === 'ingresos') {
  let ingresosTotales = 0;
  const porCatIngresos = {};

  for (const row of rows) {
    if (!enRango(row)) continue;
    const tipo = String(row.json['Tipo'] || '').trim();
    if (tipo !== 'Ingreso') continue;
    const montoOriginal = Number(row.json['Monto Original'] || 0);
    const montoArs      = Number(row.json['Monto Ars'] || 0);
    const cat           = String(row.json['Categoria'] || 'Ingresos').trim();

    // FIX: usa montoOriginal como fallback siempre
    const monto = montoArs > 0 ? montoArs : montoOriginal;

    ingresosTotales += monto;
    porCatIngresos[cat] = (porCatIngresos[cat] || 0) + monto;
  }

  const topIngresos = Object.entries(porCatIngresos)
    .sort((a,b) => b[1]-a[1])
    .map(([cat, monto]) => `  • ${cat}: $${Math.round(monto).toLocaleString('es-AR')} ARS`);

  let respIngresos = `📈 *Tus ingresos*\n\n`;
  respIngresos += `💰 *Total ingresado:* $${Math.round(ingresosTotales).toLocaleString('es-AR')} ARS\n`;
  if (topIngresos.length > 0) {
    respIngresos += `\n📋 *Por categoria:*\n${topIngresos.join('\n')}\n`;
  }
  respIngresos += `\n¿Queres saber algo mas, ${firstName}? 😊`;

  return [{ json: { chatId, mensajeBot: respIngresos } }];
}

// ── Respuesta general ─────────────────────────────────────────
const labels = {
  'total':     '📊 Tu resumen general',
  'mes':       '📅 Lo que gastaste este mes',
  'semana':    '🗓 Lo que gastaste esta semana',
  'hoy':       '☀️ Lo que gastaste hoy',
  'categoria': `🏷 Tus gastos en *${filtroCat}*`
};
const titulo = labels[filtroTipo] || '📊 Resumen';

let respuestaFinal = `${titulo}\n\n`;
if (gastosARS > 0) {
  respuestaFinal += `💵 *Gastos en ARS:* $${Math.round(gastosARS).toLocaleString('es-AR')}\n`;
}
if (gastosUSD > 0) {
  respuestaFinal += `💲 *Gastos en USD:* $${Math.round(gastosUSD).toLocaleString('es-AR')} USD`;
  if (gastosUSDenARS > 0) {
    respuestaFinal += ` (= $${Math.round(gastosUSDenARS).toLocaleString('es-AR')} ARS)`;
  }
  respuestaFinal += `\n`;
}
respuestaFinal += `💸 *Total en ARS:* $${Math.round(totalGastosARS).toLocaleString('es-AR')}\n`;
if (filtroTipo === 'total') {
  respuestaFinal += `📈 *Ingresos:* $${Math.round(ingresos).toLocaleString('es-AR')} ARS\n`;
  respuestaFinal += `⚖️ *Balance:* $${Math.round(ingresos - totalGastosARS).toLocaleString('es-AR')} ARS\n`;
}
if (topCats.length > 0) {
  respuestaFinal += `\n📋 *Por categoria:*\n${topCats.join('\n')}\n`;
}
respuestaFinal += `\n¿Queres saber algo mas, ${firstName}? 😊`;

return [{ json: { chatId, mensajeBot: respuestaFinal } }];

// ============================================================
// PREPARAR CONSULTA: leer planilla y calcular según filtro
// ============================================================
const item = $input.first().json;
const filtro = item.jsonData?.filtro_tipo || 'total';
const filtroCat = item.jsonData?.filtro_categoria || '';

return [{ json: {
  ...item,
  filtro_tipo: filtro,
  filtro_categoria: filtroCat
}}];
